from abc import ABC, abstractmethod
import anthropic

class VectorRetriever(ABC):
    """Abstract retriever — implement for each vector database."""

    @abstractmethod
    def upsert(self, chunk_id: str, embedding: list[float], payload: dict) -> None:
        ...

    @abstractmethod
    def search(self, query_embedding: list[float], filter: dict, top_k: int) -> list[dict]:
        """Return list of dicts with 'score', 'content', 'metadata' keys."""
        ...


class RAGPipeline:
    def __init__(self, retriever: VectorRetriever, embed_model: str = "text-embedding-3-small"):
        self.retriever = retriever
        self.client = anthropic.Anthropic()
        # In production, use a dedicated embedding provider
        self.embed_model = embed_model

    def embed(self, text: str) -> list[float]:
        # Use your embedding provider (e.g. OpenAI, Voyage AI, Cohere)
        raise NotImplementedError("plug in your embedding provider")

    def retrieve(self, question: str, tenant_id: str, top_k: int = 5) -> list[dict]:
        q_embedding = self.embed(question)
        return self.retriever.search(q_embedding, {"tenant_id": tenant_id}, top_k)

    def answer(self, question: str, tenant_id: str) -> str:
        chunks = self.retrieve(question, tenant_id)
        context = "

".join(c["content"] for c in chunks)
        response = self.client.messages.create(
            model="claude-opus-4-5",
            max_tokens=2048,
            system=(
                "You are a precise assistant. Answer questions using ONLY the "
                "context provided. If the answer is not in the context, say so."
            ),
            messages=[{
                "role": "user",
                "content": f"Context:
{context}

Question: {question}"
            }]
        )
        return response.content[0].text
